function openChannel(
    address payee,
    IERC20 token,
    uint256 deposit,
    address authorizedSigner,
    uint256 deadline
) external nonReentrant returns (bytes32 channelId) {
    if (payee == address(0)) revert ZeroAddress();
    if (deposit == 0) revert InvalidAmount();

    channelId = keccak256(
        abi.encodePacked(
            msg.sender,
            payee,
            address(token),
            block.timestamp,
            channelCounter++
        )
    );

    token.safeTransferFrom(msg.sender, address(this), deposit);

    channels[channelId] = Channel({
        payer: msg.sender,
        payee: payee,
        authorizedSigner: authorizedSigner,
        token: token,
        deposit: deposit,
        settled: 0,
        gracePeriodEnd: 0,
        finalized: false
    });

    emit ChannelOpened(
        channelId,
        msg.sender,
        payee,
        address(token),
        deposit,
        authorizedSigner
    );
}
